final:
module up_counter_enable(
    input clk,
    input rst_n,
    input enable,
    output reg [9:0] count
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
        if (!rst_n)
            count <= 10'b0000000000;
        else if (enable)
            count <= count + 1;
    end

endmodule
